import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate("/login");
  };

  return (
    <nav
      style={{
        background: "#ffffff",
        borderBottom: "1px solid #eaeaea",
        padding: "14px 24px",
        boxShadow: "0 2px 10px rgba(0,0,0,0.03)",
      }}
    >
      <div
        className="container flex"
        style={{ alignItems: "center" }}
      >
        {/* LOGO */}
        <Link
          to="/"
          style={{
            fontSize: "20px",
            fontWeight: "600",
            color: "#111",
          }}
        >
          SubManager
        </Link>

        {/* RIGHT SIDE */}
        <div className="flex" style={{ gap: "16px" }}>
          {user ? (
            <>
              <Link to="/tasks" style={{ color: "#555" }}>
                Subscriptions
              </Link>

              <Link to="/profile" style={{ color: "#555" }}>
                Profile
              </Link>

              {/* ADMIN */}
              {user.role === "admin" && (
                <Link
                  to="/admin"
                  style={{
                    color: "#4f46e5",
                    fontWeight: "500",
                  }}
                >
                  Admin
                </Link>
              )}

              {/* ROLE BADGE */}
              <span
                style={{
                  background: "#f3f4f6",
                  padding: "4px 10px",
                  borderRadius: "999px",
                  fontSize: "12px",
                  color: "#555",
                }}
              >
                {user.role}
              </span>

              {/* LOGOUT */}
              <button
                onClick={handleLogout}
                className="btn-danger"
              >
                Logout
              </button>
            </>
          ) : (
            <>
              <Link to="/login" style={{ color: "#555" }}>
                Login
              </Link>

              <Link
                to="/register"
                className="btn-primary"
              >
                Register
              </Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
